  ('social-worker-moex-01912', 'social-worker', 'social-worker-moex-107-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '研究者想要研究個案管理過程，他可能挑選大、中、小個案量的方案，都市、郊區、鄉鎮的方案，以及 一些新的、舊的方案等，這是何種質性抽樣？', '["深度抽樣", "同質性抽樣", "理論抽樣", "最大變異抽樣"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:11+00:00", "source_pdf_sha1": "3f540dda9f6b", "answer_pdf_sha1": "b6e329770714", "source_family": "moex-gov-tw", "moex": {"exam_code": "107030", "c": "107", "s": "0606", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作研究方法", "year": "107", "exam_name": "107年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
