  ('social-worker-moex-01914', 'social-worker', 'social-worker-moex-107-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '非介入性研究（unobtrusive research）可以減少下列那種問題？', '["研究者對所研究現象的影響", "無效的操作化概念", "不可信的測量", "佐證"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:11+00:00", "source_pdf_sha1": "3f540dda9f6b", "answer_pdf_sha1": "b6e329770714", "source_family": "moex-gov-tw", "moex": {"exam_code": "107030", "c": "107", "s": "0606", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作研究方法", "year": "107", "exam_name": "107年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-01915', 'social-worker', 'social-worker-moex-107-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '某研究者聲稱他所做的調查研究保證是匿名，他寄出1500份郵寄問卷，結果回收500份，為了提高問卷 回收率，他決定寄出催覆問卷，請問他應該再寄出幾份問卷？', '["1500份", "1000份", "500份", "250份"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:11+00:00", "source_pdf_sha1": "3f540dda9f6b", "answer_pdf_sha1": "b6e329770714", "source_family": "moex-gov-tw", "moex": {"exam_code": "107030", "c": "107", "s": "0606", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作研究方法", "year": "107", "exam_name": "107年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-01916', 'social-worker', 'social-worker-moex-107-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '下列何種質性研究的範型是著重在詳盡與精確的描述，而非解釋？', '["俗民方法論（ethnomethodology）", "自然論（naturalism）", "紮根理論（grounded theory）", "民族誌（ethnography）"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:11+00:00", "source_pdf_sha1": "3f540dda9f6b", "answer_pdf_sha1": "b6e329770714", "source_family": "moex-gov-tw", "moex": {"exam_code": "107030", "c": "107", "s": "0606", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作研究方法", "year": "107", "exam_name": "107年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-01917', 'social-worker', 'social-worker-moex-107-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '某機構每2年進行一次臺灣家庭暴力事件的調查，持續10年，想了解家庭暴力事件這10年來是否有所 改善，該機構所做的調查是屬於下列何種研究？', '["需求評估（needs assessment study）", "成本效益研究（cost-benefit study）", "後勤研究（logistical study）", "監測研究（monitoring study）"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:11+00:00", "source_pdf_sha1": "3f540dda9f6b", "answer_pdf_sha1": "b6e329770714", "source_family": "moex-gov-tw", "moex": {"exam_code": "107030", "c": "107", "s": "0606", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作研究方法", "year": "107", "exam_name": "107年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-01918', 'social-worker', 'social-worker-moex-107-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '不管研究者如何小心設計問卷，仍可能會犯錯。為避免犯錯，預試（pretest）問卷很重要，下列關於預試 問卷敘述何者正確？', '["人數可以10個左右或更少，對象的背景需相似於正式問卷要調查的對象", "要用隨機抽樣的方式選取預試對象", "參加過預試問卷的對象須再受測正式問卷", "進行預試問卷時只要單純挑出錯誤就好"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:11+00:00", "source_pdf_sha1": "3f540dda9f6b", "answer_pdf_sha1": "b6e329770714", "source_family": "moex-gov-tw", "moex": {"exam_code": "107030", "c": "107", "s": "0606", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作研究方法", "year": "107", "exam_name": "107年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-01919', 'social-worker', 'social-worker-moex-107-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '有關內容分析法的優點，下列何者錯誤？', '["可以影響到被研究的對象", "可以節省時間和金錢", "容易修正錯誤", "很適合研究的過程歷時長久的事件"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:11+00:00", "source_pdf_sha1": "3f540dda9f6b", "answer_pdf_sha1": "b6e329770714", "source_family": "moex-gov-tw", "moex": {"exam_code": "107030", "c": "107", "s": "0606", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作研究方法", "year": "107", "exam_name": "107年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 26, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-01920', 'social-worker', 'social-worker-moex-107-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '對不同調查方法的比較，下列敘述何者錯誤？', '["面對面訪問調查回覆率高", "電話調查比面對面訪問成本高", "線上調查對敏感問題有匿名功能", "郵寄問卷調查比線上調查成本高又費時"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:11+00:00", "source_pdf_sha1": "3f540dda9f6b", "answer_pdf_sha1": "b6e329770714", "source_family": "moex-gov-tw", "moex": {"exam_code": "107030", "c": "107", "s": "0606", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作研究方法", "year": "107", "exam_name": "107年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 27, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-01921', 'social-worker', 'social-worker-moex-107-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '田野研究基於不同的理論典範而有不同的研究設計，認為社會真實是社會建構出來的，社會真實的描述 除了被研究者所陳述的故事訊息外，還需要了解其故事背後的社會意義。是屬於下列何理論典範？', '["俗民方法論", "紮根理論", "建制民族誌", "自然主義"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:11+00:00", "source_pdf_sha1": "3f540dda9f6b", "answer_pdf_sha1": "b6e329770714", "source_family": "moex-gov-tw", "moex": {"exam_code": "107030", "c": "107", "s": "0606", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作研究方法", "year": "107", "exam_name": "107年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 28, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-01922', 'social-worker', 'social-worker-moex-107-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '一種研究設計的重點是讓被研究者在參與研究的過程中，有機會為解決自身群體的問題或創造群體的自 身利益，而採取一連串的行動。是指何種研究方法？', '["個案研究方法", "行動研究", "參與觀察研究", "單案研究法"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:11+00:00", "source_pdf_sha1": "3f540dda9f6b", "answer_pdf_sha1": "b6e329770714", "source_family": "moex-gov-tw", "moex": {"exam_code": "107030", "c": "107", "s": "0606", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作研究方法", "year": "107", "exam_name": "107年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 29, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-01923', 'social-worker', 'social-worker-moex-107-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '為了有效評估日益嚴重的離婚問題，研究者研究目標是要形成造成離婚的基礎理論，研究是否離婚者的 人格、婚姻模式、問題解決模式具有基本上的特質，這種以形成理論為基礎的研究，是指下列何者？', '["基礎性研究評估", "應用性研究評估", "總結性評估", "形成性評估"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:11+00:00", "source_pdf_sha1": "3f540dda9f6b", "answer_pdf_sha1": "b6e329770714", "source_family": "moex-gov-tw", "moex": {"exam_code": "107030", "c": "107", "s": "0606", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作研究方法", "year": "107", "exam_name": "107年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 30, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-01924', 'social-worker', 'social-worker-moex-107-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '觀察者在一段特定時間內，直接觀察目標行為，而且記錄每一次發生所持續的時間長度，是直接觀察法 常用的那一種記錄方法？', '["等距記錄法", "頻率記錄法", "持續記錄法", "強度記錄法"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:11+00:00", "source_pdf_sha1": "3f540dda9f6b", "answer_pdf_sha1": "b6e329770714", "source_family": "moex-gov-tw", "moex": {"exam_code": "107030", "c": "107", "s": "0606", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作研究方法", "year": "107", "exam_name": "107年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 31, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
